import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How is a lease payment calculated?", a: "A lease payment is based on depreciation during the lease plus a finance charge, reduced by any down payment." },
  { q: "What is residual value in a lease?", a: "Residual value is the asset's expected value at the end of the lease. Higher residual value usually lowers the payment." },
  { q: "What is money factor in leasing?", a: "Money factor is the lease finance rate. A rough APR equivalent is money factor multiplied by 2400." },
  { q: "When is leasing better than buying?", a: "Leasing may be better when you want lower payments, short-term use, newer assets, or less long-term ownership responsibility." },
  { q: "What fees are included in a lease?", a: "Leases can include acquisition fees, documentation fees, taxes, registration, insurance requirements, and end-of-lease charges." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
function lease(value: number, residualPct: number, factor: number, months: number, down: number) { const residual = value * residualPct / 100; const cap = Math.max(0, value - down); const depreciation = (cap - residual) / months; const finance = (cap + residual) * factor; const monthly = depreciation + finance; return { residual, monthly, total: monthly * months + down, finance, depreciation }; }
function loan(value: number, apr: number, months: number) { const r = apr / 100 / 12; return r === 0 ? value / months : value * r / (1 - Math.pow(1 + r, -months)); }

export default function LeaseCalculator() {
  useCurrencyVersion();
  const [value, setValue] = useState(40000);
  const [residual, setResidual] = useState(60);
  const [moneyFactor, setMoneyFactor] = useState(0.0025);
  const [term, setTerm] = useState(36);
  const [down, setDown] = useState(3000);
  const result = useMemo(() => lease(value, residual, moneyFactor, term, down), [value, residual, moneyFactor, term, down]);
  const buyPayment = loan(Math.max(0, value - down), moneyFactor * 2400, 60);
  const terms = [24, 36, 48, 60];
  return (
    <>
      <SEOHead title="Free Lease Calculator Online - Calculate Monthly Lease Payments Instantly | CalcHive" description="Free online lease calculator. Calculate monthly lease payments for cars, equipment and real estate with lease vs buy comparison for any asset value and term instantly. 100% free, no signup required." canonical="/lease-calculator" keywords="free lease calculator, monthly lease payment calculator free online, car lease calculator free, equipment lease calculator free, lease vs buy calculator free online" category="Financial Calculators" breadcrumbName="Free Lease Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Lease Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate lease payments for cars, equipment, and other assets with a lease vs buy comparison.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Asset value</label><input type="number" value={value} onChange={(e) => setValue(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Residual value (%)</label><input type="number" value={residual} onChange={(e) => setResidual(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Money factor</label><input type="number" step="0.0001" value={moneyFactor} onChange={(e) => setMoneyFactor(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Lease term months</label><input type="number" value={term} onChange={(e) => setTerm(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Down payment</label><input type="number" value={down} onChange={(e) => setDown(Number(e.target.value))} className={inputClass} /></div></div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly Lease Payment</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.monthly)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total lease cost</p><p className="text-lg font-extrabold text-foreground">{money(result.total)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Residual value</p><p className="text-lg font-extrabold text-foreground">{money(result.residual)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Buy payment estimate</p><p className="text-lg font-extrabold text-foreground">{money(buyPayment)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Monthly Lease Payments for Free</h2><p className="text-muted-foreground leading-relaxed">Estimate depreciation plus finance charge across the lease term, then compare it with buying.</p><h2 className="text-2xl font-bold text-foreground">How Residual Value Affects Your Lease Payment</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Lease Payment on $40,000 Asset at Different Terms and Residuals</caption><thead className="bg-muted/60"><tr>{["Lease Term", "50% Residual Payment", "60% Residual Payment", "70% Residual Payment", "Total Lease Cost at 50%"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{terms.map((m) => { const r50 = lease(40000, 50, 0.0025, m, 0); return <tr key={m}><td className="py-2.5 px-3 font-semibold">{m} months</td><td className="py-2.5 px-3">{money(r50.monthly)}</td><td className="py-2.5 px-3">{money(lease(40000, 60, 0.0025, m, 0).monthly)}</td><td className="py-2.5 px-3">{money(lease(40000, 70, 0.0025, m, 0).monthly)}</td><td className="py-2.5 px-3">{money(r50.total)}</td></tr>; })}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Universal Lease Payment Calculator for Everyone</h2><p className="text-muted-foreground leading-relaxed">Use this for vehicle, equipment, and property lease estimates when you know asset value, residual, term, and money factor.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/lease-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


